<?php require "vendor/autoload.php"; $app = require "bootstrap/app.php"; $app->make(Illuminate\Contracts\Console\Kernel::class)->bootstrap(); foreach(App\Models\Product::all() as $p) { if(is_array($p->images)) { $new = []; foreach($p->images as $i) { $new[] = str_replace("http://localhost/storage/products/", asset("storage/products/"), $i); } $p->update(["images" => $new]); } } echo "Done\n";
